checker_dsl:
EXISTS (`BinaryExpr comparison`) {
  EXISTS (`Expr left`) {
    EXISTS (`Expr right`) {
      AND {
        (`comparison is either a ComparisonExpr (like <, >, <=, >=) or an EqualityTest (like ==, !=)`),
        (`left is the left operand of comparison`),
        (`right is the right operand of comparison`),
        EXISTS (`Expr left2`) {
          EXISTS (`Expr right2`) {
            AND {
              (`left2 = left and right2 = right`),
              OR {
                AND {
                  (`left2 is a Literal expression`),
                  (`right2 is a Literal expression`),
                  (`the string value of left2 equals the string value of right2`)
                },
                EXISTS (`VarAccess leftVar`) {
                  EXISTS (`VarAccess rightVar`) {
                    EXISTS (`Variable v`) {
                      AND {
                        (`leftVar = left2 and rightVar = right2`),
                        EXISTS (`VarAccess leftVar2`) {
                          EXISTS (`VarAccess rightVar2`) {
                            EXISTS (`Variable v1`) {
                              EXISTS (`Variable v2`) {
                                AND {
                                  (`leftVar2 = leftVar and rightVar2 = rightVar and v1 = v and v2 = v`),
                                  EXISTS (`Expr left3`) {
                                    EXISTS (`Expr right3`) {
                                      AND {
                                        (`left3 = leftVar2 and right3 = rightVar2`),
                                        OR {
                                          EXISTS (`BinaryExpr binop`) {
                                            AND {
                                              (`binop is either a ComparisonExpr or an EqualityTest`),
                                              (`left3 is the left operand of binop`),
                                              (`right3 is the right operand of binop`)
                                            }
                                          },
                                          EXISTS (`Expr leftParent`) {
                                            EXISTS (`Expr rightParent`) {
                                              AND {
                                                (`leftParent is the parent expression of left3`),
                                                (`rightParent is the parent expression of right3`),
                                                (`leftParent and rightParent are in a "toCompare" relationship`)
                                              }
                                            }
                                          }
                                        }
                                      }
                                    }
                                  },
                                  (`leftVar2 accesses variable v1 and rightVar2 accesses variable v2`)
                                }
                              }
                            }
                          }
                        },
                        OR {
                          EXISTS (`VarAccess leftQual`) {
                            EXISTS (`VarAccess rightQual`) {
                              EXISTS (`Variable qualVar`) {
                                AND {
                                  (`leftQual is the qualifier expression of leftVar`),
                                  (`rightQual is the qualifier expression of rightVar`),
                                  (`leftQual and rightQual access the same variable qualVar`)
                                }
                              }
                            }
                          },
                          AND {
                            (`leftVar accesses a local variable`),
                            (`rightVar accesses a local variable`)
                          }
                        }
                      }
                    }
                  }
                },
                EXISTS (`BinaryExpr bLeft`) {
                  EXISTS (`BinaryExpr bRight`) {
                    AND {
                      (`bLeft = left2 and bRight = right2`),
                      (`bLeft has the same operator kind as bRight`),
                      EXISTS (`Expr bLeftLeft`) {
                        EXISTS (`Expr bRightLeft`) {
                          EXISTS (`Expr bLeftRight`) {
                            EXISTS (`Expr bRightRight`) {
                              AND {
                                (`bLeftLeft is the left operand of bLeft`),
                                (`bRightLeft is the left operand of bRight`),
                                (`bLeftRight is the right operand of bLeft`),
                                (`bRightRight is the right operand of bRight`),
                                (`bLeftLeft and bRightLeft are "equal" expressions`),
                                (`bLeftRight and bRightRight are "equal" expressions`)
                              }
                            }
                          }
                        }
                      }
                    }
                  }
                }
              }
            }
          }
        }
      }
    }
  }
}
